import { mathMax } from '../core/zc-constants';
import { invokeFunction } from '../utils/zcutils';

export function getPlotBound(chartObj) {
    var l = -chartObj.scrolledX || 0,
        t = -chartObj.scrolledY || 0;
    return {
        left: l,
        top: t,
        right: getPlotSize(chartObj, 'width'),
        bottom: getPlotSize(chartObj, 'height')
    };
}

export function getPlotSize(chartObj, type, plotarea, gridSize, customPlotSize) {
    plotarea = plotarea || (chartObj && chartObj.plotarea);
    var plotareaSize = gridSize || plotarea[type];
    var customSize = invokeFunction(customPlotSize || (chartObj && chartObj.systemConf.chart[type]), chartObj);
    if (customSize == null || isNaN(customSize)) {
        return plotareaSize;
    }
    return mathMax(plotareaSize, +customSize);
}
